mapper.select:
SELECT m.*
FROM message_inbox m
WHERE (
-- 个人消息：接收者是当前用户
m.receiver_id = #{userId}
OR
-- 群发消息：接收者是null或0（表示所有人）
(m.receiver_id IS NULL OR m.receiver_id = 0)
)

    AND m.message_type = #{messageType}


    AND m.status = #{status}

ORDER BY m.create_time DESC

SELECT m.*
FROM message_inbox m
WHERE m.sender_id = #{userId}

    AND m.message_type = #{messageType}


    AND m.status = #{status}

ORDER BY m.create_time DESC

SELECT * FROM message_inbox WHERE message_id IN
#{messageId}
AND deleted = 0

mapper.update:
UPDATE message_inbox SET status = 3, deleted = 1, update_time = #{updateTime} WHERE message_id IN
#{messageId}
AND (receiver_id = #{userId} OR sender_id = #{userId}) AND deleted = 0
